9470	\begin{lemma}
9471	[Local vanishing of the evaluated augmented {\v C}ech homology]
9472	  \label{lem:cechSection_isZero_homology}
9473	  \lean{AlgebraicGeometry.cechSection_isZero_homology}
9474	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
9475	    lem:isZero_homology_of_homotopy_id_zero}
9476	  Let \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) for some index \(i\). Then for every
9477	  degree \(p\) the homology \(H^p(D^\bullet)\) of the augmented {\v C}ech complex evaluated at
9478	  \(V\) (the complex \(D^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso}) is a zero
9479	  object; equivalently \(D^\bullet\) carries a contracting homotopy \(\mathrm{id}_{D^\bullet}
9480	  \simeq 0\). This is the residual obligation of Step~3 of
9481	  Lemma~\ref{lem:cech_augmented_resolution}.
9482	\end{lemma}
9483	\begin{proof}
9484	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
9485	    lem:isZero_homology_of_homotopy_id_zero}
9486	  By Lemma~\ref{lem:cechSection_complex_iso} the evaluated complex \(D^\bullet\) is
9487	  isomorphic to the augmented concrete section {\v C}ech complex \(D'^\bullet_{\mathrm{aug}}\).
9488	  The hypothesis \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) places \(V\) inside one cover
9489	  member, so Lemma~\ref{lem:cechSection_contractible} gives a contracting homotopy
9490	  \(\mathrm{id}_{D'^\bullet_{\mathrm{aug}}} \simeq 0\); transporting it across the complex
9491	  isomorphism yields \(\mathrm{id}_{D^\bullet} \simeq 0\).
9492	  Lemma~\ref{lem:isZero_homology_of_homotopy_id_zero} then makes
9493	  \(H^p(D^\bullet)\) a zero object in every degree.
9494	\end{proof}
