9498	\begin{lemma}[Pushforward sections are sections over the preimage]
9499	  \label{lem:pushforward_obj_obj_mathlib}
9500	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_obj_obj}
9501	  \mathlibok
9502	  \textit{Provided by Mathlib.}
9503	  For a morphism \(f : X \to Y\), an \(\mathcal{O}_X\)-module \(\mathcal{M}\), and an open
9504	  \(U \subseteq Y\), the sections of the pushforward \(f_*\mathcal{M}\) over \(U\) coincide
9505	  definitionally with the sections of \(\mathcal{M}\) over the preimage:
9506	  \(\Gamma(U, f_*\mathcal{M}) = \Gamma(f^{-1}(U), \mathcal{M})\).
9507	\end{lemma}
