9509	\begin{lemma}[Pullback along an open immersion is the restriction functor]
9510	  \label{lem:restrictFunctorIsoPullback_mathlib}
9511	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
9512	  \mathlibok
9513	  \textit{Provided by Mathlib.}
9514	  For an open immersion \(f : X \to Y\), the restriction functor
9515	  \(\operatorname{restrictFunctor} f : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) is
9516	  naturally isomorphic to the module pullback functor \(f^* = \operatorname{pullback} f\). In
9517	  particular \(f^*\mathcal{M} \cong \mathcal{M}.\operatorname{restrict} f\) for every
9518	  \(\mathcal{O}_Y\)-module \(\mathcal{M}\).
9519	\end{lemma}
