9521	\begin{lemma}[Evaluation of a sheaf of modules preserves products]
9522	  \label{lem:evaluation_preserves_products_mathlib}
9523	  \lean{SheafOfModules.evaluationPreservesLimitsOfShape}
9524	  \mathlibok
9525	  \textit{Provided by Mathlib.}
9526	  For a sheaf of rings on a site and any object \(U\), the evaluation (sections-at-\(U\))
9527	  functor \(\operatorname{evaluation}\,U : \operatorname{SheafOfModules} \to \mathrm{Ab}\)
9528	  preserves limits of every shape; in particular it preserves products, so \(\Gamma(U,
9529	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(U, N_\sigma)\).
